// Calculate previous month range (runs 1 hour after TG-119/120)
const now = new Date();
const reportDate = now.toISOString().split('T')[0];

const prevMonthEnd = new Date(now.getFullYear(), now.getMonth(), 0);
const prevMonthStart = new Date(now.getFullYear(), now.getMonth() - 1, 1);

const fmt = (d) => d.toISOString().split('T')[0];
const monthLabel = prevMonthStart.toLocaleString('en-US', { month: 'long', year: 'numeric' });

return [{ json: {
  reportDate,
  monthStart: fmt(prevMonthStart),
  monthEnd: fmt(prevMonthEnd),
  monthLabel,
  nowIso: now.toISOString()
} }];

// Assemble "What The System Learned This Month" digest
const dates = $('Calculate Month Range').first().json;
const reportsRaw = $('Fetch Monthly Sub-Reports').first().json;
const winnersRaw = $('Fetch A/B Test Winners').first().json;
const anomaliesRaw = $('Fetch Anomalies Detected').first().json;

const reports = Array.isArray(reportsRaw.body) ? reportsRaw.body : (Array.isArray(reportsRaw) ? reportsRaw : []);
const winners = Array.isArray(winnersRaw.body) ? winnersRaw.body : (Array.isArray(winnersRaw) ? winnersRaw : []);
const anomalies = Array.isArray(anomaliesRaw.body) ? anomaliesRaw.body : (Array.isArray(anomaliesRaw) ? anomaliesRaw : []);

// Parse sub-reports by type
const reportsByType = {};
for (const r of reports) {
  if (!reportsByType[r.report_type]) reportsByType[r.report_type] = [];
  reportsByType[r.report_type].push(r.report_data || {});
}

// --- Extract from TG-119 monthly_trend ---
const trendReports = reportsByType['monthly_trend'] || [];
const latestTrend = trendReports[0] || {};
const kpisTracked = latestTrend.kpis_tracked || 0;
const topGainers = latestTrend.top_gainers || [];
const topDecliners = latestTrend.top_decliners || [];

// --- Extract from TG-120 channel_roi ---
const roiReports = reportsByType['channel_roi'] || [];
const latestROI = roiReports[0] || {};
const totalRevenue = latestROI.total_revenue || 0;
const totalCost = latestROI.total_cost || 0;
const overallROI = latestROI.overall_roi_pct || 0;
const channelData = latestROI.channels || [];

// --- Extract weekly sub-reports ---
const weeklyRevenueReports = reportsByType['revenue_attribution'] || [];
const weeklyAdReports = reportsByType['ad_performance'] || [];
const weeklyAbReports = reportsByType['ab_test_results'] || [];
const weeklySmartReports = reportsByType['what_got_smarter'] || [];

const fmt = (n, d) => {
  if (n === undefined || n === null) return '\u2014';
  return Number(n).toLocaleString('en-US', { maximumFractionDigits: d || 0 });
};

// --- Top-level metrics ---
const topMetrics = [
  { label: 'A/B Tests Completed', value: fmt(winners.length), change: '' },
  { label: 'Anomalies Caught', value: fmt(anomalies.length), change: '' },
  { label: 'Monthly Revenue', value: totalRevenue > 0 ? '$' + fmt(totalRevenue, 2) : '\u2014', change: overallROI > 0 ? overallROI + '% ROI' : '' },
  { label: 'Reports Generated', value: fmt(reports.length), change: '' }
];

// --- Section 1: A/B Tests Completed ---
const abHighlights = [];
if (winners.length > 0) {
  for (const w of winners) {
    const winnerName = w.winner === 'a' ? (w.variant_a_name || 'Variant A') : (w.winner === 'b' ? (w.variant_b_name || 'Variant B') : (w.winner || 'TBD'));
    abHighlights.push(`"${w.test_name}" \u2014 Winner: ${winnerName} (${w.channel || 'unknown'} channel)`);
  }
} else {
  abHighlights.push('No A/B tests completed this month \u2014 consider launching new experiments');
}

// --- Section 2: Revenue Trends ---
const revenueHighlights = [];
if (totalRevenue > 0) {
  revenueHighlights.push('Total monthly revenue: $' + fmt(totalRevenue, 2));
  if (totalCost > 0) {
    revenueHighlights.push('Marketing spend: $' + fmt(totalCost, 2) + ' (ROI: ' + overallROI + '%)');
  }
  // Top channel
  if (channelData.length > 0) {
    const sorted = [...channelData].sort((a, b) => (b.revenue || 0) - (a.revenue || 0));
    if (sorted[0] && sorted[0].revenue > 0) {
      revenueHighlights.push('Top channel: ' + (sorted[0].channel || 'unknown').replace(/_/g, ' ') + ' ($' + fmt(sorted[0].revenue, 2) + ')');
    }
  }
} else {
  revenueHighlights.push('Revenue tracking building baseline \u2014 ensure TG-107 daily sync is running');
}

// --- Section 3: KPI Trends ---
const trendHighlights = [];
if (topGainers.length > 0) {
  for (const g of topGainers.slice(0, 2)) {
    trendHighlights.push('Improved: ' + (g.metric || '').replace(/_/g, ' ') + ' +' + (g.changePct || 0) + '%');
  }
}
if (topDecliners.length > 0) {
  for (const d of topDecliners.slice(0, 2)) {
    trendHighlights.push('Declined: ' + (d.metric || '').replace(/_/g, ' ') + ' ' + (d.changePct || 0) + '%');
  }
}
if (trendHighlights.length === 0) {
  trendHighlights.push('KPI trending active \u2014 month-over-month comparisons accumulating');
}

// --- Section 4: Anomalies ---
const anomalyHighlights = [];
if (anomalies.length > 0) {
  // Group by severity
  const critical = anomalies.filter(a => a.severity === 'critical');
  const warnings = anomalies.filter(a => a.severity === 'warning');
  anomalyHighlights.push(anomalies.length + ' anomal' + (anomalies.length === 1 ? 'y' : 'ies') + ' detected (' + critical.length + ' critical, ' + warnings.length + ' warnings)');
  // Show top 3
  for (const a of anomalies.slice(0, 3)) {
    anomalyHighlights.push((a.severity || 'info') + ': ' + (a.metric_name || 'unknown').replace(/_/g, ' ') + ' deviated ' + (a.deviation_pct || 0) + '%');
  }
} else {
  anomalyHighlights.push('No anomalies detected \u2014 all KPIs within expected ranges');
}

// --- Section 5: Intelligence System Health ---
const healthHighlights = [];
healthHighlights.push(reports.length + ' intelligence reports generated this month');
healthHighlights.push(Object.keys(reportsByType).length + ' report types active: ' + Object.keys(reportsByType).join(', '));
if (weeklySmartReports.length > 0) {
  healthHighlights.push(weeklySmartReports.length + ' weekly "What Got Smarter" digests delivered');
}
healthHighlights.push('All monthly workflows (TG-119, TG-120, TG-121) operational');

// --- Actions ---
const actions = [];
if (winners.length === 0) {
  actions.push('Launch new A/B tests \u2014 no experiments completed this month');
}
if (topDecliners.length > 0 && topDecliners[0].absChange > 20) {
  actions.push('Investigate ' + topDecliners[0].metric.replace(/_/g, ' ') + ' decline (' + topDecliners[0].changePct + '%)');
}
if (anomalies.length > 5) {
  actions.push('High anomaly count (' + anomalies.length + ') \u2014 review alerting thresholds or investigate systemic issue');
}
if (totalRevenue === 0) {
  actions.push('No revenue tracked \u2014 verify TG-107 revenue sync and revenue_attribution table');
}
if (actions.length === 0) {
  actions.push('Intelligence system healthy \u2014 continue monitoring and iterating on experiments');
}

// --- Build TG-118 sections ---
const sections = [
  { type: 'metrics', title: 'Monthly Intelligence Summary', items: topMetrics },
  { type: 'highlights', title: 'A/B Tests Completed', items: abHighlights },
  { type: 'highlights', title: 'Revenue & Channel Insights', items: revenueHighlights },
  { type: 'highlights', title: 'KPI Trends', items: trendHighlights },
  { type: 'highlights', title: 'Anomalies Caught', items: anomalyHighlights },
  { type: 'highlights', title: 'System Health', items: healthHighlights },
  { type: 'actions', title: 'Actions for Next Month', items: actions }
];

return [{ json: {
  report_title: 'What The System Learned This Month',
  report_subtitle: dates.monthLabel + ' | TotalGuard Monthly Intelligence Digest',
  sections,
  storePayload: {
    report_type: 'learning_report',
    report_date: dates.reportDate,
    report_data: {
      month: dates.monthLabel,
      ab_tests_completed: winners.length,
      ab_test_winners: winners.map(w => ({ name: w.test_name, channel: w.channel, winner: w.winner })),
      anomalies_detected: anomalies.length,
      anomalies_critical: anomalies.filter(a => a.severity === 'critical').length,
      total_revenue: totalRevenue,
      total_cost: totalCost,
      overall_roi_pct: overallROI,
      kpis_tracked: kpisTracked,
      top_gainers: topGainers.slice(0, 3),
      top_decliners: topDecliners.slice(0, 3),
      reports_generated: reports.length,
      report_types: Object.keys(reportsByType),
      weekly_digests: weeklySmartReports.length
    },
    generated_by: 'TG-121'
  }
} }];
